import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import axios from "axios";
import "./styles/Books.css";

function BooksDetails() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [book, setBook] = useState(null);
  const [loading, setLoading] = useState(true);
  const [transaction, setTransaction] = useState(null);

  const userId = localStorage.getItem("userId");
  const role = localStorage.getItem("role");

  // 🔥 FETCH BOOK DETAILS
  useEffect(() => {
    axios
      .get(`http://localhost:5000/api/books/${id}`)
      .then((res) => {
        setBook(res.data);
        setLoading(false);
      })
      .catch((err) => {
        console.log(err);
        setLoading(false);
      });
  }, [id]);

  // 🔥 CHECK IF BOOK IS ALREADY BORROWED BY THIS STUDENT
  useEffect(() => {
    if (!userId) return;

    axios
      .get(`http://localhost:5000/api/transactions/student/${userId}`)
      .then((res) => {
        const active = res.data.find(
          (t) => t.book._id === id && t.status === "issued"
        );
        if (active) {
          setTransaction(active);
        }
      })
      .catch((err) => console.log(err));
  }, [id, userId]);

  // 🔥 BORROW BOOK
  const borrowBook = async () => {
    try {
      if (!userId) {
        alert("Please login first.");
        return;
      }

      await axios.post(
        "http://localhost:5000/api/transactions/borrow",
        {
          studentId: userId,
          bookId: id,
        }
      );

      alert("Book borrowed successfully!");
      window.location.reload();

    } catch (err) {
      alert(err.response?.data?.message || "Error borrowing book");
    }
  };

  // 🔥 RETURN BOOK
  const returnBook = async () => {
    try {
      const res = await axios.post(
        "http://localhost:5000/api/transactions/return",
        {
          transactionId: transaction._id,
        }
      );

      alert(
        res.data.fine > 0
          ? `Book returned. Fine: ₹${res.data.fine}`
          : "Book returned successfully!"
      );

      window.location.reload();

    } catch (err) {
      alert("Error returning book");
    }
  };

  // 🔥 ADD TO WISHLIST
  const handleWishlist = async () => {
    try {
      if (!userId) {
        alert("Please login first.");
        return;
      }

      await axios.post("http://localhost:5000/api/wishlist/add", {
        studentId: userId,
        bookId: id,
      });

      alert("Added to Wishlist ❤️");

    } catch (err) {
      alert("Error adding to wishlist");
    }
  };

  if (loading) return <p>Loading book details...</p>;
  if (!book) return <p>Book not found.</p>;

  return (
    <div className="books-page">
      <div className="details-layout">

        {/* LEFT CARD */}
        <div className="detail-card">

  {/* ❤️ Wishlist Heart */}
  {role === "Student" && (
    <button
  className="heart-btn"
  onClick={handleWishlist}
  title="Add to Wishlist"
>
  <i className="bi bi-heart-fill"></i>
</button>
  )}

  <img src={book.cover} alt={book.title} />
  <h2>{book.title}</h2>
  <p>{book.author}</p>

  <p className="status">
    Status:{" "}
    <span className={book.available ? "avail" : "not-avail"}>
      {book.available ? "Available" : "Not Available"}
    </span>
  </p>

</div>

        {/* RIGHT PANEL */}
        <div className="book-info-panel">
          <div className="info-block">
            <h3>About the Book</h3>
            <p>{book.about}</p>
          </div>

          <div className="info-block">
            <h3>About the Author</h3>
            <p>{book.authorInfo}</p>
          </div>
        </div>
      </div>

      {/* ACTION BUTTONS */}
      <div className="action-buttons">

  <button className="borrow-btn" onClick={borrowBook}>
    Borrow Book
  </button>

  <button className="wishlist-btn" onClick={handleWishlist}>
    ❤️ Add to Wishlist
  </button>

  <button className="back-btn" onClick={() => navigate(-1)}>
    ← Back to Library
  </button>

</div>
    </div>
  );
}

export default BooksDetails;
